const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\(\);
  const page = await browser.newPage\(\);
  await page.setViewportSize\({ width: 1440, height: 900 }\);
  await page.goto\('http://localhost:3000/insights'\);
  await page.waitForLoadState\('networkidle'\);

  // Screenshot section 3 \(framework - around y:900-1400\)
  await page.screenshot\({ path: '/tmp/sec3-framework.png', clip: { x: 0, y: 900, width: 1440, height: 600 } }\);

  // Screenshot section 7 \(blueprint cards - around y:2400-3000\)
  await page.screenshot\({ path: '/tmp/sec7-blueprint.png', clip: { x: 0, y: 2400, width: 1440, height: 700 } }\);

  // Screenshot section 8 \(core concepts\)
  await page.screenshot\({ path: '/tmp/sec8-concepts.png', clip: { x: 0, y: 3100, width: 1440, height: 800 } }\);

  await browser.close\(\);
  console.log\('done'\);
}\)\(\);
" 2>/dev/null)
